class SecureInterceptor(grpc.ServerInterceptor):
    """
    Server interceptor that adds security headers and handles
    unhandled exceptions at the framework level.
    """

    def intercept_service(self, continuation, handler_call_details):
        """Intercept all calls for security logging."""
        method = handler_call_details.method
        logger.info("Incoming gRPC call: method=%s", sanitize_for_logging(method))

        # Validate method name format
        if not re.match(r'^/[a-zA-Z0-9_./-]+$', method):
            logger.warning("Rejected call with invalid method name: %s", sanitize_for_logging(method))
            return None

        return continuation(handler_call_details)


def create_secure_server(port=50051, max_workers=10):
    """
    Create a gRPC server with secure configuration.
    
    In production:
    - Use TLS/mTLS (server_credentials with certificates)
    - Set appropriate resource limits
    - Configure health checking
    """
    interceptor = SecureInterceptor()

    server = grpc.server(
        futures.ThreadPoolExecutor(max_workers=max_workers),
        interceptors=[interceptor],
        options=[
            # Limit message sizes to prevent resource exhaustion
            ('grpc.max_send_message_length', 4 * 1024 * 1024),  # 4MB
            ('grpc.max_receive_message_length', 4 * 1024 * 1024),  # 4MB
            ('grpc.max_metadata_size', 8 * 1024),  # 8KB metadata limit
        ]
    )

    # In production, use secure port with TLS:
    # server_credentials = grpc.ssl_server_credentials(...)
    # server.add_secure_port(f'[::]:{port}', server_credentials)

    # For demonstration only - in production ALWAYS use TLS
    server.add_insecure_port(f'[::]:{port}')

    logger.info("Server configured on port %d", port)
    return server


